prices = {'apple': 1.2, 'banana': 0.5, 'cherry': 3.0}

# Loop over keys
for fruit in prices.keys():
    print(fruit)           # apple  banana  cherry

# Loop over values
for price in prices.values():
    print(price)           # 1.2  0.5  3.0

# Loop over key-value pairs (most useful!)
for fruit, price in prices.items():
    print(f'{fruit}: ${price:.2f}')
# apple: $1.20
# banana: $0.50
# cherry: $3.00

# Each contact is itself a dictionary
contacts = {
    'Alice': {'phone': '123-456', 'city': 'Kyiv'},
    'Bob':   {'phone': '789-012', 'city': 'Lviv'}
}

# Access nested values with two keys
print(contacts['Alice']['phone'])  # 123-456
print(contacts['Bob']['city'])     # Lviv

# Loop over nested dict
for name, info in contacts.items():
    print(f'{name} — {info["city"]}, {info["phone"]}')
